123	// Get all team info
124	function getTeams() {
125	  const teams = [];
126	  if (!fs.existsSync(TEAMS_DIR)) return teams;
127	
128	  const teamDirs = fs.readdirSync(TEAMS_DIR);
129	
130	  for (const teamName of teamDirs) {
131	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
132	    try {
133	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
134	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
135	
136	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
137	      if (fs.existsSync(taskListPath)) {
138	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
139	        for (const taskFile of taskFiles) {
140	          try {
141	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
142	            taskStatus.total++;
143	            if (task.status === 'completed') taskStatus.completed++;
144	            else if (task.status === 'in_progress') taskStatus.inProgress++;
145	            else if (task.status === 'pending') taskStatus.pending++;
146	          } catch {}
147	        }
148	      }
149	
150	      teams.push({
151	        name: teamName,
152	        description: config.description || '',
153	        memberCount: config.members?.length || 0,
154	        taskStatus
155	      });
156	    } catch {}
157	  }
158	
159	  return teams;
160	}
