162	// Build environment from user settings
163	function buildEnvScript() {
164	  let settingsEnv = {};
165	  try {
166	    const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
167	    const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
168	    settingsEnv = settings.env || {};
169	  } catch (e) {
170	    console.error('Could not read settings.json:', e.message);
171	  }
172	
173	  return {
174	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1',
175	    ANTHROPIC_BASE_URL: settingsEnv.ANTHROPIC_BASE_URL || '',
176	    ANTHROPIC_AUTH_TOKEN: settingsEnv.ANTHROPIC_AUTH_TOKEN || '',
177	    ANTHROPIC_API_KEY: settingsEnv.ANTHROPIC_API_KEY || '',
178	    ANTHROPIC_MODEL: settingsEnv.ANTHROPIC_MODEL || '',
179	    CLAUDE_BIN: settingsEnv.CLAUDE_BIN || path.join(process.env.HOME, '.local', 'bin', 'claude')
180	  };
181	}
