209	// Parse CLI args string into array (handles --flag and "quoted strings")
210	function parseCliArgs(input) {
211	  const args = [];
212	  let current = '';
213	  let inQuote = false;
214	
215	  for (let i = 0; i < input.length; i++) {
216	    const c = input[i];
217	    if (c === '"' && !inQuote) {
218	      inQuote = true;
219	    } else if (c === '"' && inQuote) {
220	      inQuote = false;
221	      args.push(current);
222	      current = '';
223	    } else if (c === ' ' && !inQuote) {
224	      if (current) args.push(current);
225	      current = '';
226	    } else {
227	      current += c;
228	    }
229	  }
230	  if (current) args.push(current);
231	  return args;
232	}
