234	// Spawn a detached background claude process
235	function spawnBackgroundProcess(name, cmd) {
236	  const env = buildEnvScript();
237	  const logFile = path.join(__dirname, `logs/${name}-${Date.now()}.log`);
238	  const logsDir = path.join(__dirname, 'logs');
239	  if (!fs.existsSync(logsDir)) fs.mkdirSync(logsDir, { recursive: true });
240	
241	  const parts = parseCliArgs(cmd);
242	
243	  // Build a clean environment — omit CLAUDECODE to prevent nested-session rejection
244	  const cleanEnv = {
245	    ...process.env,
246	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS,
247	    ANTHROPIC_BASE_URL: env.ANTHROPIC_BASE_URL,
248	    ANTHROPIC_AUTH_TOKEN: env.ANTHROPIC_AUTH_TOKEN,
249	    ANTHROPIC_API_KEY: env.ANTHROPIC_API_KEY,
250	    ANTHROPIC_MODEL: env.ANTHROPIC_MODEL
251	  };
252	  delete cleanEnv.CLAUDECODE;
253	  delete cleanEnv.CLAUDE_CODE_SSE_PORT;
254	  delete cleanEnv.CLAUDE_CODE_ENTRYPOINT;
255	
256	  try {
257	    const child = spawn(env.CLAUDE_BIN, parts, {
258	      detached: true,
259	      stdio: ['ignore', 'pipe', 'pipe'],
260	      env: cleanEnv
261	    });
262	
263	    const logStream = fs.createWriteStream(logFile, { flags: 'a' });
264	    child.stdout.pipe(logStream);
265	    child.stderr.pipe(logStream);
266	
267	    child.unref();
268	    return { pid: child.pid, logFile };
269	  } catch (e) {
270	    console.error('Spawn failed:', e.message);
271	    return { pid: null, logFile, error: e.message };
272	  }
273	}
