285	// API: Wake up a team by re-spawning the agent in background
286	app.post('/api/wake/:name', (req, res) => {
287	  try {
288	    const teamName = req.params.name;
289	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
290	
291	    if (!fs.existsSync(teamConfigPath)) {
292	      return res.status(404).json({ success: false, error: 'Team not found' });
293	    }
294	
295	    const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
296	    if (!config.members || config.members.length === 0) {
297	      return res.status(400).json({ success: false, error: 'Team has no members' });
298	    }
299	
300	    // Check if Claude CLI is compatible with the current API provider
301	    const canSpawn = checkClaudeCompatibility();
302	
303	    let results = [];
