307	
308	      if (!canSpawn) {
309	        // Mark as active without spawning — user needs to resume manually
310	        member.backgroundId = `${name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-manual`;
311	        results.push({
312	          name: member.name,
313	          logFile: null,
314	          status: 'registered',
315	          note: 'OpenRouter requires manual resume. Run: claude -r ' + teamName
316	        });
317	        continue;
318	      }
319	
320	      let cmd;
321	      if (name.toLowerCase() === 'trevor' || agentType === 'manager' || agentType === 'trevor') {
322	        cmd = '--agent=trevor -p "Resume your previous work as manager agent."';
323	      } else {
324	        cmd = `-p "Wake up agent ${name}, continue previous work."`;
325	      }
326	
327	      const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
328	      const backgroundId = `${safeName}-${Date.now()}`;
329	      const { pid, logFile } = spawnBackgroundProcess(backgroundId, cmd);
330	
331	      if (pid) savePid(`${teamName}.pid`, pid);
332	      console.log(`Woke up ${name} (PID: ${pid})`);
333	
334	      member.backgroundId = backgroundId;
335	      results.push({ name: member.name, logFile, status: 'waking_up' });
336	    }
337	
338	    fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));
339	
340	    res.json({ success: true, message: `Woke up team "${teamName}"`, agents: results, canSpawn });
341	  } catch (err) {
342	    res.status(500).json({ success: false, error: err.message });
343	  }
