369	// API: Spawn agent
370	// Since OpenRouter doesn't support Claude CLI context management,
371	// this creates a registered agent entry that users can manage from the dashboard.
372	// Status shows as "registered" — users can resume the session manually.
373	app.post('/api/spawn', (req, res) => {
374	  try {
375	    const { name, role, prompt, description } = req.body;
376	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
377	
378	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
379	    const teamName = `agent-${safeName}-${Date.now()}`;
380	    const backgroundId = `spawn-${safeName}-${Date.now()}`;
381	
382	    const canSpawn = checkClaudeCompatibility();
383	    let logFile = null;
384	    let pid = null;
385	
386	    if (canSpawn) {
387	      // Build the claude command
388	      let cmd;
389	      if (name.toLowerCase() === 'trevor' || role === 'manager' || role === 'trevor') {
390	        cmd = `--agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
391	      } else {
392	        cmd = `"${fullPrompt.replace(/"/g, '\\"')}"`;
393	      }
394	
395	      const result = spawnBackgroundProcess(backgroundId, cmd);
396	      pid = result.pid;
397	      logFile = result.logFile;
398	    }
399	
400	    if (pid) savePid(`${teamName}.pid`, pid);
401	
402	    // Save description
403	    if (description) {
404	      const descriptions = loadDescriptions();
405	      descriptions[name] = description;
406	      saveDescriptions(descriptions);
407	    }
408	
409	    // Create team entry so the dashboard can discover this agent
410	    const teamDir = path.join(TEAMS_DIR, teamName);
411	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
412	
413	    fs.mkdirSync(teamDir, { recursive: true });
414	    fs.mkdirSync(taskListDir, { recursive: true });
415	
416	    const teamConfig = {
417	      description: description || `${name} — ${role} agent`,
418	      leaderSessionId: null,
419	      createdAt: Date.now(),
420	      backgroundId,
421	      members: [{
422	        agentId: `agent-${safeName}`,
423	        name,
424	        agentType: role || 'general-purpose',
425	        backgroundId
426	      }]
427	    };
428	    fs.writeFileSync(
429	      path.join(teamDir, 'config.json'),
430	      JSON.stringify(teamConfig, null, 2)
431	    );
432	
433	    res.json({
434	      success: true,
435	      message: canSpawn
436	        ? `Agent "${name}" spawned in background`
437	        : `Agent "${name}" registered (OpenRouter — resume manually)`,
438	      name,
439	      teamName,
440	      logFile,
441	      canSpawn,
442	      resumeCommand: canSpawn ? null : `claude -r ${teamName}`
443	    });
444	  } catch (err) {
445	    res.status(500).json({ success: false, error: err.message });
446	  }
447	});
