484	// Open a new Terminal.app tab and run a command via osascript
485	// Writes command to .sh + AppleScript to temp files to avoid all quoting issues
486	function openTerminalTab(title, command) {
487	  const tmpDir = path.join(__dirname, '.tmp');
488	  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
489	
490	  // Write the actual command to a shell script
491	  const shellFile = path.join(tmpDir, `launch-${Date.now()}.sh`);
492	  fs.writeFileSync(shellFile, `#!/bin/bash\necho "=== Agent: ${title} ==="\n${command}\n`, 'utf8');
493	  fs.chmodSync(shellFile, '755');
494	
495	  // Escape the path for AppleScript (no quotes needed if no spaces in tmp path)
496	  const safeShellPath = shellFile.replace(/"/g, '\\"').replace(/\\/g, '\\\\');
497	  const safeTitle = title.replace(/"/g, '\\"');
498	
499	  const appleScript = `tell application "Terminal"
500	    set winId to do script "${safeShellPath}"
501	    set custom title of winId to "${safeTitle}"
502	    set title displays custom title of winId to true
503	    set miniaturized of winId to true
504	end tell
505	`;
506	  const scriptFile = path.join(tmpDir, `launch-${Date.now()}.scpt`);
507	  fs.writeFileSync(scriptFile, appleScript, 'utf8');
508	
509	  try {
510	    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 10000 });
511	    // Clean up after a delay (Terminal has already sourced the files)
512	    setTimeout(() => {
513	      try { fs.unlinkSync(shellFile); } catch {}
514	      try { fs.unlinkSync(scriptFile); } catch {}
515	    }, 10000);
516	    return true;
517	  } catch (e) {
518	    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
519	    try { fs.unlinkSync(shellFile); } catch {}
520	    try { fs.unlinkSync(scriptFile); } catch {}
521	    return false;
522	  }
523	}
