560	// API: Generate launch script that opens all agents in Terminal.app
561	app.get('/api/launch-script', (req, res) => {
562	  const agents = getRunningAgents();
563	  if (agents.length === 0) {
564	    return res.status(204).send('No agents to launch');
565	  }
566	
567	  const claudePath = path.join(process.env.HOME, '.local', 'bin', 'claude');
568	
569	  let script = `#!/bin/bash\n# Agent Office — Launch All Agents\n`;
570	  script += `cd "${__dirname}"\n`;
571	  script += `export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1\n\n`;
572	
573	  agents.forEach((agent) => {
574	    const isTrevor = agent.name.toLowerCase() === 'trevor';
575	    let cmd = `claude -r ${agent.teamName}`;
576	    if (isTrevor) cmd += ' --agent=trevor';
577	    cmd += ' --permission-mode acceptEdits';
578	    script += `echo "Launching ${agent.name}..." && ${cmd} &\nsleep 0.5\n`;
579	  });
580	
581	  script += `\necho "All agents launched! Press any key to close this window..."\nread -n 1\n`;
582	
583	  res.setHeader('Content-Type', 'text/plain');
584	  res.setHeader('Content-Disposition', 'attachment; filename="launch-agents.command"');
585	  res.send(script);
586	});
