671	// Main render loop
672	function render() {
673	  // Update player movement
674	  let dx = 0, dy = 0;
675	  const spd = player.speed;
676	  player.moving = false;
677	
678	  if (keys['w'] || keys['arrowup']) { dy = -spd; player.dir = 'up'; player.moving = true; }
679	  else if (keys['s'] || keys['arrowdown']) { dy = spd; player.dir = 'down'; player.moving = true; }
680	  else if (keys['a'] || keys['arrowleft']) { dx = -spd; player.dir = 'left'; player.moving = true; }
681	  else if (keys['d'] || keys['arrowright']) { dx = spd; player.dir = 'right'; player.moving = true; }
682	
683	  if (player.moving) {
684	    player.pixelBob += 0.15;
685	
686	    // Check X movement
687	    const newX = player.x + dx;
688	    if (isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.3)) &&
689	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.3)) &&
690	        isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.8)) &&
691	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.8))) {
692	      player.x = newX;
693	    }
694	
695	    // Check Y movement
696	    const newY = player.y + dy;
697	    if (isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.3)) &&
698	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.3)) &&
699	        isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.8)) &&
700	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.8))) {
701	      player.y = newY;
702	    }
703	  }
704	
705	  // Update camera to follow player
706	  camX = player.x * TILE - canvas.width / 2 + TILE / 2;
707	  camY = player.y * TILE - canvas.height / 2 + TILE / 2;
708	
709	  // Clamp camera
710	  camX = Math.max(0, Math.min(camX, COLS * TILE - canvas.width));
711	  camY = Math.max(0, Math.min(camY, ROWS * TILE - canvas.height));
712	
713	  // Clear
714	  ctx.clearRect(0, 0, canvasW, canvasH);
715	
716	  // Draw tiles
717	  const startCol = Math.max(0, Math.floor(camX / TILE));
718	  const startRow = Math.max(0, Math.floor(camY / TILE));
719	  const endCol = Math.min(COLS - 1, Math.ceil((camX + canvasW) / TILE));
720	  const endRow = Math.min(ROWS - 1, Math.ceil((camY + canvasH) / TILE));
721	
722	  for (let y = startRow; y <= endRow; y++) {
723	    for (let x = startCol; x <= endCol; x++) {
724	      const tile = officeMap[y][x];
725	      if (tile !== undefined) drawTile(x, y, tile);
726	    }
727	  }
728	
729	  // Draw sports floors on top of tiles
730	  drawSportsFloor();
731	
732	  // Draw agent sprites on their desks
733	  const agentPositions = getAgentPositions();
734	  agentPositions.forEach(({ x, y, agent }) => {
735	    const screenX = x * TILE - camX + 8;
736	    const screenY = y * TILE - camY + 8;
737	    drawAgentSprite(agent, screenX, screenY);
738	  });
739	
740	  // Draw player on top
741	  drawPlayer();
742	
743	  // Draw room labels as floor text
744	  ctx.fillStyle = 'rgba(255,255,255,0.3)';
745	  ctx.font = '4px "Press Start 2P", monospace';
746	
747	  // Check for interaction hint
748	  const tileAtPlayer = getTileAt(Math.floor(player.x + 0.5), Math.floor(player.y + 0.5));
749	  if (tileAtPlayer === 6) {
750	    showTooltip('Press E to interact');
751	  }
752	
753	  requestAnimationFrame(render);
754	}
