  text-align: center;
}

.detail-info p {
  font-family: var(--font-title);
  font-size: 0.7rem;
  margin: 6px 0;
  color: var(--text-secondary);
}

/* --- Scrollbar - Pixel Style --- */
::-webkit-scrollbar {
  width: 12px;
}

::-webkit-scrollbar-track {
  background: var(--gb-black);
  border: var(--border-thin) solid var(--gb-dark);
}

::-webkit-scrollbar-thumb {
  background: var(--gb-mid);
  border: var(--border-thin) solid var(--gb-dark);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--gb-light);
}

/* --- Selection (Pokemon style blue highlight) --- */
::selection {
  background: var(--poke-blue);
  color: #fff;
}

/* --- Responsive --- */
@media (max-width: 768px) {
  .hud {
    flex-direction: column;
    gap: var(--spacing);
    align-items: flex-start;
  }

  .hud-right {
    margin-left: 0;
