}

/* --- Battle Transition Animation --- */
@keyframes battleFlash {
  0% { background: #fff; }
  100% { background: transparent; }
}

.battle-flash {
  animation: battleFlash 0.4s steps(3);
}

/* Level up animation for agents */
@keyframes levelUp {
  0% { transform: scale(1); filter: brightness(1); }
  25% { transform: scale(1.05); filter: brightness(1.5); }
  50% { transform: scale(1); filter: brightness(1.3); }
  100% { transform: scale(1); filter: brightness(1); }
