  ctx.fillRect(ox + b / 2, oy + b * 3 - 2, b, b);
  ctx.fillRect(ox + b * 2, oy + b * 3 - 2, b, b);
  // Work boots
  ctx.fillStyle = '#3e2723';
  ctx.fillRect(ox + b / 2 - 2, oy + b * 3 + 2, b + 4, 5);
