  ctx.fillRect(24 * TILE - camX + 4, 18 * TILE - camY, 3 * TILE - 8, 4 * TILE - 8);
  // Hoop
  ctx.fillStyle = '#ff5722';
  ctx.beginPath();
  ctx.arc(26 * TILE - camX, 20 * TILE - camY, 6, 0, Math.PI * 2);
