  // Circle
  ctx.strokeStyle = '#fff';
  ctx.beginPath();
  ctx.arc(23 * TILE - camX, 20 * TILE - camY, 8, 0, Math.PI * 2);
  ctx.stroke();

  ctx.fillStyle = 'rgba(255,255,255,0.5)';
  ctx.fillText('BASKETBALL', 22 * TILE - camX, 18 * TILE - camY);

  // Resting room label (x: 29-34, y: 3-9)
