/* ═══════════════════════════════════════════════════
   AGENT OFFICE - PIXIEMON EDITION
   Pixel Art Dashboard Theme
   ═══════════════════════════════════════════════════ */

/* --- Reset & Variables --- */
:root {
  /* Game Boy Color palette + Pokemon Game Boy era colors */
  --gb-black: #0f380f;
  --gb-dark: #306230;
  --gb-mid: #8bac0f;
  --gb-light: #9bbc0f;
  --gb-bg: #e0f8d0;

  /* Pokemon GBC era */
  --poke-red: #ff001e;
  --poke-blue: #3c5aa6;
  --poke-yellow: #ffc400;
  --poke-gold: #e8a00e;
  --poke-dark-blue: #2a206b;
  --poke-teal: #1ba8b5;
  --poke-pink: #f44336;
  --poke-green: #4caf50;
  --poke-lime: #8bc34a;
  --poke-orange: #ff9800;
  --poke-purple: #9c27b0;
  --poke-light-purple: #ce93d8;

  /* UI */
  --panel-bg: #f0f8ff;
  --panel-border: #1a1a2e;
  --panel-inner: #e8f4fd;
  --panel-shadow: #8888aa;
  --text-primary: #1a1a2e;
  --text-secondary: #3a3a5e;
  --text-muted: #6a6a8e;

  /* Status */
  --status-working: #4caf50;
  --status-idle: #ffc400;
  --status-planning: #64b5f6;
  --status-offline: #757575;

  /* Size */
  --pixel: 4px;
  --border-thick: 4px;
  --border-thin: 2px;
  --spacing: 8px;

  /* Font */
  --font-title: 'Press Start 2P', monospace;
  --font-body: 'Press Start 2P', monospace;
}

*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  image-rendering: pixelated;
}

html {
  font-family: var(--font-body);
  font-size: 10px;
  background: var(--gb-black);
  overflow-x: hidden;
}

body {
  min-height: 100vh;
  background:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 16px,
      rgba(15, 56, 15, 0.03) 16px,
      rgba(15, 56, 15, 0.03) 17px
    ),
    repeating-linear-gradient(
      90deg,
      transparent,
      transparent 16px,
      rgba(15, 56, 15, 0.03) 16px,
      rgba(15, 56, 15, 0.03) 17px
    ),
    linear-gradient(135deg, #0f380f 0%, #1a4a1a 20%, #0f380f 40%, #1a2a1a 60%, #0f4a0f 80%, #0f380f 100%);
  background-attachment: fixed;
  color: var(--text-primary);
}

/* --- Loading Overlay --- */
.loading-overlay {
  position: fixed;
  inset: 0;
  background: var(--poke-blue);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  opacity: 1;
  transition: opacity 0.5s steps(4);
}

.loading-overlay.hidden {
  opacity: 0;
  pointer-events: none;
}

.loading-text {
  font-family: var(--font-title);
  font-size: 1.4rem;
  color: var(--poke-yellow);
  animation: flashText 0.8s steps(2) infinite;
}

@keyframes flashText {
  0%, 50% { opacity: 1; }
  51%, 100% { opacity: 0; }
}

/* --- Game Container --- */
.game-container {
  max-width: 1400px;
  margin: 0 auto;
  padding: var(--spacing) var(--spacing) calc(var(--spacing) * 2);
}

/* --- HUD Header --- */
.hud {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing);
  background: var(--poke-blue);
  border: var(--border-thick) solid var(--panel-border);
  border-bottom-left-radius: 2px;
  border-bottom-right-radius: 2px;
  margin-bottom: var(--spacing);
  position: relative;
  box-shadow:
    0 4px 0 rgba(0,0,0,0.3),
    inset 0 2px 0 rgba(255,255,255,0.1);
}

.hud::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 0;
  right: 0;
  height: 4px;
  background: var(--poke-dark-blue);
}

.hud-left {
  display: flex;
  align-items: baseline;
  gap: var(--spacing);
}

.title {
  font-family: var(--font-title);
  font-size: 1.8rem;
  color: #ffffff;
  text-shadow:
    2px 2px 0 var(--poke-dark-blue),
    -1px -1px 0 var(--poke-red);
  letter-spacing: 2px;
  line-height: 1.4;
}

.subtitle {
  font-family: var(--font-title);
  font-size: 0.7rem;
  color: var(--poke-yellow);
  text-shadow: 1px 1px 0 #000;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.hud-right {
  display: flex;
  gap: var(--spacing);
  margin-left: var(--spacing);
}

/* --- Buttons - Pixel Style --- */
.btn {
  font-family: var(--font-title);
  font-size: 0.8rem;
  padding: 10px 16px;
  cursor: pointer;
  border: var(--border-thin) solid var(--panel-border);
  background: #fff;
  color: var(--text-primary);
  text-transform: uppercase;
  letter-spacing: 1px;
  transition: all 0.1s steps(1);
  position: relative;
  box-shadow:
    2px 2px 0 var(--panel-border),
    inset 0 1px 0 #fff;
}

.btn:hover {
  transform: translate(1px, 1px);
  box-shadow:
    1px 1px 0 var(--panel-border),
    inset 0 1px 0 #fff;
}

.btn:active {
  transform: translate(2px, 2px);
  box-shadow: none;
}

.btn-icon {
  margin-right: 6px;
  font-size: 1.2rem;
  vertical-align: middle;
}

.btn-hire {
  background: var(--poke-red);
  color: #fff;
  border-color: #cc0000;
}

.btn-hire:hover {
  background: #ff3333;
  border-color: #aa0000;
}

/* Pixel button decorative dots */
.pixel-btn::before {
  content: '';
  position: absolute;
  top: 4px;
  left: 4px;
  width: 6px;
  height: 6px;
  background: currentColor;
  opacity: 0.2;
  box-shadow:
    8px 0 0 currentColor,
    0 8px 0 currentColor,
    8px 8px 0 currentColor;
}

/* --- Status Bar --- */
.status-bar {
  display: flex;
  align-items: center;
  gap: calc(var(--spacing) * 2);
  padding: 10px var(--spacing);
  background: #2a2a4e;
  border: var(--border-thin) solid var(--panel-border);
  margin-bottom: var(--spacing);
  flex-wrap: wrap;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.stat-label {
  font-family: var(--font-title);
  font-size: 0.6rem;
  color: var(--poke-teal);
  letter-spacing: 2px;
}

.stat-value {
  font-family: var(--font-title);
  font-size: 1.2rem;
  color: #fff;
  text-shadow: 1px 1px 0 #000;
}

.separator {
  width: 2px;
  height: 32px;
  background: var(--gb-dark);
  margin: 0 8px;
}

#currentTime {
  color: var(--gb-light);
}

/* --- Office Map (Canvas Container) --- */
.office-map-container {
  width: 100%;
  border: var(--border-thick) solid var(--panel-border);
  background: #000;
  position: relative;
  cursor: crosshair;
  overflow: hidden;
}

#officeCanvas {
  display: block;
  width: 100%;
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}

/* Walk tooltip */
.walk-tooltip {
  position: absolute;
  bottom: 12px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--panel-bg);
  border: var(--border-thin) solid var(--panel-border);
  padding: 6px 12px;
  font-family: var(--font-title);
  font-size: 0.6rem;
  color: var(--text-primary);
  box-shadow: 2px 2px 0 rgba(0,0,0,0.3);
  z-index: 10;
  transition: opacity 0.2s;
}

.walk-tooltip.hidden {
  opacity: 0;
  pointer-events: none;
}

/* --- Agent Roster --- */
.agent-roster {
  border: var(--border-thick) solid var(--panel-border);
  background: #1a1a2e;
  padding: 0;
  margin-top: var(--spacing);
}

.roster-title {
  font-family: var(--font-title);
  font-size: 1rem;
  color: var(--poke-yellow);
  text-shadow: 2px 2px 0 rgba(0,0,0,0.5);
  padding: 12px 16px;
  background: var(--poke-dark-blue);
  border-bottom: var(--border-thin) solid var(--panel-border);
  letter-spacing: 2px;
}

.roster-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 0;
  padding: 8px;
}

.roster-empty {
  grid-column: 1 / -1;
  text-align: center;
  padding: 40px 20px;
  font-family: var(--font-title);
  font-size: 0.7rem;
  color: var(--text-muted);
}

.roster-avatar-icon {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 12px;
  background: #2a2a4e;
  border-right: var(--border-thick) solid var(--panel-border);
}

.roster-icon {
  width: 40px;
  height: 40px;
  border: var(--border-thick) solid var(--panel-border);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-title);
  font-size: 1.2rem;
  color: #fff;
}

.roster-info {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px;
  flex: 1;
}

.roster-info-left {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.roster-name {
  font-family: var(--font-title);
