}

/* --- Area Headers --- */
.area-header {
  grid-column: 1 / -1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border: var(--border-thick) solid var(--panel-border);
  margin-top: 8px;
}

/* Card Header - Pokemon Name */
.card-header {
  padding: 12px;
  background: linear-gradient(180deg, #f8f8f8 0%, #e8e8e8 100%);
